const res=$input.first().json;
const slug=$('Validate').first().json.slug;
const content=res?.choices?.[0]?.message?.content||'';
let data;
try{const c=content.replace(/```json|```/g,'').trim();data=JSON.parse(c.match(/\{[\s\S]*\}/)?.[0]||c);}catch(e){return [{json:{success:false,error:'Parse failed: '+e.message,slug}}];}
if(!data.actions||!Array.isArray(data.actions)) return [{json:{success:false,error:'No actions in response',slug}}];
return [{json:{success:true,spoke:data,model:res.model,slug}}];

const db=$input.first().json;
const spoke=$('Parse Spoke').first().json.spoke;
return [{json:{success:true,spoke,saved:!!db.id,model:$('Parse Spoke').first().json.model}}];

const b=$input.first().json;
const prompt=(b.prompt||'').trim();
const code_type=b.code_type||'business_rule';
const cfg=b.config||{};
if(!prompt||prompt.length<10) return [{json:{success:false,error:'Prompt too short (min 10 chars)'}}];
const typeLabels={business_rule:'Business Rule',script_include:'Script Include',client_script:'Client Script',scheduled_job:'Scheduled Job',rest_api:'REST API',transform_map:'Transform Map Script',flow_script:'Flow Designer Script'};
const typeCtx={business_rule:`Table: ${cfg.tableName||'incident'}\nWhen: ${cfg.when||'before'}\nStructure: (function executeRule(current,previous){...})(current,previous);`,client_script:`Table: ${cfg.tableName||'incident'}\nType: ${cfg.when||'onLoad'}\nUse g_form, g_user only. No GlideRecord.`,scheduled_job:'Include error handling, gs.info() logging, batch processing.',rest_api:`Method: ${cfg.method||'GET'}\nPath: ${cfg.path||'/api/x_custom/endpoint'}\nInclude request/response handling.`,script_include:`Name: ${cfg.name||'MyHelper'}\nUse OOP pattern with Class.create()`};
return [{json:{valid:true,prompt,code_type,label:typeLabels[code_type]||code_type,type_context:typeCtx[code_type]||''}}];

const res=$input.first().json;
const code=res?.choices?.[0]?.message?.content||'';
const model=res?.model||'';
const prompt=$('Validate & Prep').first().json.prompt;
const code_type=$('Validate & Prep').first().json.code_type;
if(!code) return [{json:{success:false,error:'Empty code response'}}];
// Strip markdown if AI added it
const clean=code.replace(/^```\w*\n/,'').replace(/\n```$/,'').trim();
return [{json:{success:true,code:clean,code_type,prompt,model}}];

const b=$input.first().json;
const script=(b.script||'').trim();
const script_type=b.script_type||'server';
if(!script||script.length<20) return [{json:{success:false,error:'Script too short'}}];
return [{json:{valid:true,script:script.substring(0,3000),script_type}}];

const res=$input.first().json;
const content=res?.choices?.[0]?.message?.content||'';
let data;
try{const c=content.replace(/```json|```/g,'').trim();data=JSON.parse(c.match(/\{[\s\S]*\}/)?.[0]||c);}catch{data={summary:content,critical_issues:[],suggestions:[],overall_rating:5};}
return [{json:{success:true,...data,model:res.model}}];

const b=$input.first().json;
const msg=(b.error_message||'').trim();
const ctx=b.context||'';
if(!msg) return [{json:{success:false,error:'error_message required'}}];
return [{json:{valid:true,error_message:msg.substring(0,500),context:ctx}}];

const res=$input.first().json;
const msg=$('Validate').first().json.error_message;
const content=res?.choices?.[0]?.message?.content||'';
let data;
try{const c=content.replace(/```json|```/g,'').trim();data=JSON.parse(c.match(/\{[\s\S]*\}/)?.[0]||c);}catch{data={title:'Error Analysis',description:content,root_cause:'',fix_steps:[],category:'General',severity:'medium'};}
return [{json:{success:true,...data,source:'ai_generated',model:res.model}}];

const b=$input.first().json;
const script=(b.script||'').trim();
